parameters.jsCode:
const client = $('Por cada cliente').item.json;
const data = $input.first().json.result || {};
const reviews = (data.reviews || []);
const lastCheck = client.last_review_check ? new Date(client.last_review_check).getTime() / 1000 : 0;

const newReviews = reviews.filter(r => (r.time || 0) > lastCheck);

return newReviews.map(r => ({
  json: {
    client_id: client.id,
    client_name: client.business_name,
    author: r.author_name,
    rating: r.rating,
    text: r.text || '(sin texto)',
    time_iso: new Date((r.time || 0) * 1000).toISOString(),
    relative: r.relative_time_description,
    is_negative: r.rating <= 3,
  }
}));

